"""Interfaz de videollamada activa conectada a LiveKit."""

import json


def build_active_room_html(*, logo: str, meeting: dict, connection: dict, user: dict, demo: bool = False) -> str:
    cfg = json.dumps(
        {
            "logo": logo,
            "meetingId": str(meeting.get("id") or ""),
            "title": str(meeting.get("tema") or "Reunión VINCORA"),
            "code": str(meeting.get("id_externo") or str(meeting.get("id") or "")[:11]),
            "name": str(user.get("nombre") or "Usuario"),
            "token": str(connection.get("participant_token") or ""),
            "serverUrl": str(connection.get("server_url") or ""),
            "recordingState": str(connection.get("recording_state") or "not_configured"),
            "demo": demo,
            "isOrganizer": bool(user.get("is_organizer")),
        },
        ensure_ascii=False,
    ).replace("</", "<\\/")
    return _HTML.replace("__CONFIG__", cfg)


_HTML = r'''<!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><script src="https://cdn.jsdelivr.net/npm/livekit-client@2.20.1/dist/livekit-client.umd.js"></script><style>
*{box-sizing:border-box}html,body{margin:0;height:100%;overflow:hidden;font-family:Segoe UI,Arial,sans-serif;background:#07111e;color:#f5f7fb}.app{height:100vh;background:radial-gradient(circle at 45% 35%,#102337,#07111e 67%)}.top{height:82px;display:flex;align-items:center;gap:22px;padding:0 28px;border-bottom:1px solid #223043;background:#07111ee8}.brand{display:flex;align-items:center;gap:10px;font-size:19px;font-weight:800}.brand img{width:42px;height:42px;object-fit:contain}.sep{width:1px;height:29px;background:#7b8490}.meeting-title{font-size:15px}.code{color:#aeb7c5}.status{margin-left:auto;display:flex;gap:12px}.pill{height:42px;padding:0 18px;border:1px solid #2b394b;border-radius:18px;display:flex;align-items:center;gap:10px;background:#101a28}.record-dot{width:12px;height:12px;border-radius:50%;background:#ff6565}.ai-pill{color:#20d8e7;border-color:#0e4b58}.layout{height:calc(100vh - 82px);display:grid;grid-template-columns:1fr 112px}.stage{position:relative;padding:36px 24px 128px}.grid{height:100%;display:grid;grid-template-columns:repeat(3,1fr);grid-auto-rows:minmax(0,1fr);gap:10px}.tile{position:relative;overflow:hidden;border-radius:11px;background:linear-gradient(145deg,#263d55,#111d2c);border:1px solid #26384c}.tile.speaking{border:2px solid #7954f7;box-shadow:0 0 0 1px #1765ed}.tile video{width:100%;height:100%;object-fit:cover}.tile.local video{transform:scaleX(-1)}.fallback{position:absolute;inset:0;display:grid;place-items:center;background:linear-gradient(135deg,#21476b,#45236b);font-size:46px;font-weight:800}.name{position:absolute;left:10px;bottom:8px;padding:5px 10px;border-radius:5px;background:#09111dcc;font-size:14px}.name .mic{color:#21d98b;margin-right:7px}.rightbar{display:flex;flex-direction:column;border-left:1px solid #223043;background:#091321}.rail-button{height:150px;border:0;border-bottom:1px solid #17283a;background:transparent;color:#cdd5e1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;cursor:pointer}.rail-button.active{color:#fff;background:#101e2e}.rail-icon{font-size:27px}.badge{padding:2px 7px;border-radius:999px;background:#1765ed;font-size:11px}.bottom{position:absolute;left:50%;bottom:28px;transform:translateX(-50%);height:94px;min-width:900px;padding:10px 18px;display:flex;align-items:center;justify-content:center;gap:18px;border:1px solid #26384b;border-radius:17px;background:#0c1724ee;box-shadow:0 10px 30px #0008}.control{min-width:88px;border:0;background:transparent;color:#e6eaf0;cursor:pointer;display:flex;flex-direction:column;align-items:center;gap:8px}.control i{font-style:normal;font-size:27px}.control.off{color:#ff6a68}.control.ai{height:60px;min-width:170px;border-radius:12px;background:linear-gradient(105deg,#1765ed,#923cf2);font-weight:800;justify-content:center}.control.leave{height:60px;min-width:140px;border-radius:12px;background:#ef4b4d;font-weight:700;justify-content:center}.secure{position:absolute;bottom:33px;left:28px;color:#aab5c4}.panel{display:none;position:absolute;z-index:10;right:112px;top:82px;width:340px;height:calc(100vh - 82px);padding:20px;background:#0c1725;border-left:1px solid #25364b;box-shadow:-12px 0 30px #0005}.panel.open{display:block}.panel h2{margin:0 0 18px;font-size:19px}.panel-close{float:right;border:0;background:none;color:#fff;font-size:20px}.participant-row{padding:12px 0;border-bottom:1px solid #203044}.chat-list{height:calc(100% - 105px);overflow:auto}.chat-msg{margin:9px 0;padding:10px;border-radius:9px;background:#142236}.chat-send{position:absolute;bottom:18px;left:18px;right:18px;display:flex;gap:8px}.chat-send input{flex:1;padding:12px;border:1px solid #34465d;border-radius:8px;background:#101d2c;color:#fff}.chat-send button{border:0;border-radius:8px;background:#1765ed;color:#fff}.transcript{color:#aeb9c8;line-height:1.55}.toast{position:fixed;top:96px;left:50%;transform:translateX(-50%);padding:11px 17px;border-radius:8px;background:#162538;opacity:0;transition:.2s}.toast.show{opacity:1}.end-overlay{display:none;position:fixed;z-index:30;inset:0;align-items:center;justify-content:center;background:#020812cc}.end-overlay.open{display:flex}.end-modal{position:relative;width:min(560px,calc(100vw - 30px));padding:30px 46px 35px;border-radius:20px;background:#fff;color:#0c1b3e;text-align:center;box-shadow:0 30px 80px #0009}.end-close{position:absolute;right:25px;top:18px;border:0;background:none;color:#53627d;font-size:30px}.end-logo{width:104px;height:104px;padding:17px;border-radius:50%;background:#f0edff}.end-modal h2{margin:17px 0 10px;font-size:30px}.end-description{margin:0 auto 22px;max-width:450px;color:#65738c;line-height:1.45}.end-stats{display:flex;justify-content:center;margin-bottom:20px;border:1px solid #d5ddea;border-radius:8px}.end-stats span{padding:13px 20px;border-right:1px solid #d5ddea}.end-stats span:last-child{border:0}.end-options{text-align:left}.end-options label{display:block;margin:13px 0}.end-options input{width:19px;height:19px;margin-right:10px;accent-color:#1765ed}.end-note{margin:20px 0;padding-top:15px;border-top:1px solid #d8dfeb;color:#718098;font-size:12px}.end-action{width:100%;height:54px;margin-top:10px;border-radius:7px;font-weight:800;font-size:17px}.end-all{border:0;background:#e82e34;color:#fff}.end-self{border:1.5px solid #1765ed;background:#fff;color:#1765ed}.end-cancel{border:0;background:#fff;color:#1765ed}@media(max-width:1000px){.grid{grid-template-columns:repeat(2,1fr)}.bottom{min-width:calc(100% - 160px);gap:7px}.control{min-width:65px;font-size:11px}.secure{display:none}}@media(max-width:650px){.layout{grid-template-columns:1fr}.rightbar{display:none}.stage{padding:12px 12px 105px}.grid{grid-template-columns:1fr}.top{padding:0 12px}.code,.sep,.recording{display:none}.bottom{left:12px;right:12px;transform:none;min-width:0;overflow-x:auto;justify-content:flex-start}.control.ai{min-width:115px}.panel{right:0;width:100%}.end-modal{padding:25px 20px}}
</style></head><body><div class="app"><header class="top"><div class="brand"><img id="logo"><span>VINCORA Meet</span></div><span class="sep"></span><span class="meeting-title" id="title"></span><span class="sep"></span><span class="code" id="code"></span><div class="status"><div class="pill recording"><span class="record-dot"></span><span id="record-status">Listo para grabar</span></div><div class="pill ai-pill">✦ VINCORA IA activa</div></div></header><div class="layout"><main class="stage"><div class="grid" id="grid"></div><div class="secure">♢ Audio y video protegidos</div><nav class="bottom"><button class="control" id="mic"><i>♩</i><span>Micrófono</span></button><button class="control" id="camera"><i>▣</i><span>Cámara</span></button><button class="control" id="share"><i>▧</i><span>Compartir</span></button><button class="control" id="record"><i>◉</i><span>Grabar</span></button><button class="control" id="reaction"><i>☺</i><span>Reacciones</span></button><button class="control" id="hand"><i>✋</i><span>Levantar mano</span></button><button class="control ai" id="ai">✦ VINCORA IA</button><button class="control leave" id="leave">☎ Finalizar</button></nav></main><aside class="rightbar"><button class="rail-button" data-panel="participants"><span class="rail-icon">♧ <span class="badge" id="count">1</span></span><span>Participantes</span></button><button class="rail-button" data-panel="chat"><span class="rail-icon">◯ <span class="badge" id="chat-count">0</span></span><span>Chat</span></button><button class="rail-button" data-panel="transcription"><span class="rail-icon">▤</span><span>Transcripción</span></button><button class="rail-button" data-panel="assistant"><span class="rail-icon">✦</span><span>IA</span></button></aside></div></div>
<section class="panel" id="participants"><button class="panel-close">×</button><h2>Participantes</h2><div id="participant-list"></div></section><section class="panel" id="chat"><button class="panel-close">×</button><h2>Chat</h2><div class="chat-list" id="chat-list"></div><div class="chat-send"><input id="chat-input" placeholder="Escribe un mensaje"><button id="chat-send">Enviar</button></div></section><section class="panel" id="transcription"><button class="panel-close">×</button><h2>Transcripción en vivo</h2><p class="transcript">La IA está tomando notas. Los segmentos confirmados aparecerán aquí con participante y tiempo exacto.</p><div id="transcript-list"></div></section><section class="panel" id="assistant"><button class="panel-close">×</button><h2>VINCORA IA</h2><p class="transcript">Durante la reunión identificaré temas, posibles acuerdos y tareas. Nada se aprobará sin revisión humana.</p></section><div class="end-overlay" id="end-overlay"><div class="end-modal"><button class="end-close" id="end-close">×</button><img class="end-logo" id="end-logo"><h2>¿Finalizar la reunión?</h2><p class="end-description">VINCORA cerrará la sala y preparará la información disponible para el informe.</p><div class="end-stats"><span>◷ <b id="end-duration">0 min</b></span><span>♧ <b id="end-count">1 participante</b></span><span id="end-recording">◉ Grabación no activa</span></div><div class="end-options"><label><input type="checkbox" id="end-report" checked>Generar informe con IA ✦</label><label><input type="checkbox" id="end-notify" checked>Notificar a los participantes cuando esté listo</label></div><div class="end-note">♙ Solo los usuarios autorizados podrán acceder a la información de la reunión.</div><button class="end-action end-all" id="end-all">Finalizar para todos</button><button class="end-action end-self" id="end-self">Salir solo yo</button><button class="end-action end-cancel" id="end-cancel">Cancelar</button></div></div><div class="toast" id="toast"></div>
<script>const cfg=__CONFIG__,LK=window.LivekitClient;document.getElementById('logo').src=cfg.logo;document.getElementById('end-logo').src=cfg.logo;document.getElementById('title').textContent=cfg.title;document.getElementById('code').textContent=cfg.code;const recordingActive=['iniciada','active','starting'].includes(String(cfg.recordingState).toLowerCase());const recordingText=recordingActive?'Grabando':(cfg.recordingState==='error'?'Grabación no disponible':'Grabación no configurada');document.getElementById('record-status').textContent=recordingText;document.getElementById('end-recording').textContent='◉ '+(recordingActive?'Grabación activa':recordingText);let room=null,chats=0;const joinedAt=Date.now(),grid=document.getElementById('grid');const toast=t=>{const e=document.getElementById('toast');e.textContent=t;e.classList.add('show');setTimeout(()=>e.classList.remove('show'),2200)};function appUrl(query){let base=null;try{const href=window.parent.location.href;if(/^https?:/i.test(href))base=new URL(href)}catch(e){}if(!base){const origins=window.location.ancestorOrigins;if(origins&&origins.length)base=new URL('/',origins[0])}if(!base&&/^https?:/i.test(document.referrer))base=new URL(document.referrer);if(!base){toast('No se pudo determinar la dirección de VINCORA');return null}base.search=query;base.hash='';return base.toString()}function navigateApp(query){const url=appUrl(query);if(!url)return;const opened=window.open(url,'_blank','noopener');if(!opened)toast('Permite ventanas emergentes para continuar')}const initials=n=>n.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase();
function tile(identity,name,local=false){let el=document.getElementById('tile-'+CSS.escape(identity));if(el)return el;el=document.createElement('div');el.id='tile-'+identity;el.className='tile'+(local?' local':'');el.innerHTML='<div class="fallback">'+initials(name)+'</div><span class="name"><span class="mic">●</span>'+name+'</span>';grid.appendChild(el);return el}function attach(track,p){if(track.kind!=='video')return;const el=tile(p.identity,p.name||p.identity,p===room.localParticipant);el.querySelectorAll('video').forEach(v=>v.remove());const v=track.attach();v.autoplay=true;v.playsInline=true;el.appendChild(v)}function setCount(n){document.getElementById('count').textContent=n;document.getElementById('end-count').textContent=n+' participante'+(n===1?'':'s')}function updatePeople(){if(!room)return;const people=[room.localParticipant,...room.remoteParticipants.values()];setCount(people.length);document.getElementById('participant-list').innerHTML=people.map(p=>'<div class="participant-row">'+(p.name||p.identity)+(p===room.localParticipant?' (Tú)':'')+'</div>').join('')}
async function connect(){if(cfg.demo){['Ana García','Luis Torres','María Gómez','Diego Ramírez','Sofía Vega'].forEach((n,i)=>tile('demo'+i,n));tile('local',cfg.name,true);document.getElementById('count').textContent='6';return}if(!LK||!cfg.token)return toast('No fue posible iniciar LiveKit');room=new LK.Room({adaptiveStream:true,dynacast:true});room.on(LK.RoomEvent.TrackSubscribed,(t,pub,p)=>attach(t,p));room.on(LK.RoomEvent.ParticipantConnected,p=>{tile(p.identity,p.name||p.identity);updatePeople()});room.on(LK.RoomEvent.ParticipantDisconnected,p=>{document.getElementById('tile-'+CSS.escape(p.identity))?.remove();updatePeople()});room.on(LK.RoomEvent.ActiveSpeakersChanged,ps=>{document.querySelectorAll('.tile').forEach(e=>e.classList.remove('speaking'));ps.forEach(p=>document.getElementById('tile-'+CSS.escape(p.identity))?.classList.add('speaking'))});room.on(LK.RoomEvent.DataReceived,(data,p)=>{try{const m=JSON.parse(new TextDecoder().decode(data));if(m.type==='chat')addChat(p?.name||'Participante',m.text);if(m.type==='hand')toast((p?.name||'Un participante')+' levantó la mano')}catch(e){}});await room.connect(cfg.serverUrl,cfg.token);tile(room.localParticipant.identity,cfg.name,true);await room.localParticipant.setCameraEnabled(true);await room.localParticipant.setMicrophoneEnabled(true);const pub=room.localParticipant.getTrackPublication(LK.Track.Source.Camera);if(pub?.track)attach(pub.track,room.localParticipant);updatePeople()}
async function toggle(source,button){if(!room)return;const enabled=room.localParticipant.isCameraEnabled&&source==='camera'?room.localParticipant.isCameraEnabled:room.localParticipant.isMicrophoneEnabled;if(source==='camera')await room.localParticipant.setCameraEnabled(!enabled);else await room.localParticipant.setMicrophoneEnabled(!enabled);button.classList.toggle('off',enabled)}document.getElementById('mic').onclick=e=>toggle('mic',e.currentTarget);document.getElementById('camera').onclick=e=>toggle('camera',e.currentTarget);document.getElementById('share').onclick=async()=>{if(!room)return;const enabled=room.localParticipant.isScreenShareEnabled;await room.localParticipant.setScreenShareEnabled(!enabled);toast(enabled?'Dejaste de compartir':'Estás compartiendo tu pantalla')};document.getElementById('record').onclick=()=>toast(recordingActive?'La grabación del servidor está activa':recordingText);document.getElementById('reaction').onclick=()=>toast('👏 Reacción enviada');document.getElementById('hand').onclick=async()=>{if(room)await room.localParticipant.publishData(new TextEncoder().encode(JSON.stringify({type:'hand'})),{reliable:true});toast('Mano levantada')};
const endOverlay=document.getElementById('end-overlay');document.getElementById('leave').onclick=()=>{document.getElementById('end-duration').textContent=Math.max(1,Math.round((Date.now()-joinedAt)/60000))+' min';endOverlay.classList.add('open')};const closeEnd=()=>endOverlay.classList.remove('open');document.getElementById('end-close').onclick=closeEnd;document.getElementById('end-cancel').onclick=closeEnd;document.getElementById('end-self').onclick=()=>{room?.disconnect();navigateApp('?pagina=Reuniones')};document.getElementById('end-all').style.display=cfg.isOrganizer?'block':'none';document.getElementById('end-all').onclick=()=>{const report=document.getElementById('end-report').checked?'1':'0',notify=document.getElementById('end-notify').checked?'1':'0';room?.disconnect();navigateApp('?finalizar_reunion='+encodeURIComponent(cfg.meetingId)+'&generar_informe='+report+'&notificar='+notify)};if(cfg.demo)setTimeout(()=>setCount(6),0);
function addChat(name,text){const e=document.createElement('div');e.className='chat-msg';e.innerHTML='<b>'+name+'</b><br>'+text;document.getElementById('chat-list').appendChild(e);chats++;document.getElementById('chat-count').textContent=chats}document.getElementById('chat-send').onclick=async()=>{const i=document.getElementById('chat-input'),text=i.value.trim();if(!text)return;addChat(cfg.name,text);if(room)await room.localParticipant.publishData(new TextEncoder().encode(JSON.stringify({type:'chat',text})),{reliable:true});i.value=''};document.querySelectorAll('.rail-button').forEach(b=>b.onclick=()=>{document.querySelectorAll('.panel').forEach(p=>p.classList.remove('open'));document.getElementById(b.dataset.panel).classList.add('open')});document.querySelectorAll('.panel-close').forEach(b=>b.onclick=()=>b.parentElement.classList.remove('open'));connect().catch(e=>toast('No se pudo conectar: '+e.message));</script></body></html>'''
